import React from "react";

const Blessings = () => (
  <section id="blessings" className="card">
    <h3>Your Blessings</h3>
    <p>
      Your presence is the greatest gift we could ask for. If you wish to share your blessings,
      kind words, or wishes, we would be honored to receive them on our special day.
    </p>
  </section>
);

export default Blessings;
